mapper.select:
select   u.email ,  u.password, a.auth
from     appuser u  left join  authorities a  on   u.email = a.email
where    u.email = #{email}

mapper.update:
update appuser
mbti_type_id=#{mbtiTypeId} , ufile = #{ufile} , nickname=#{nickname} , mobile=#{mobile} , provider=#{provider} , provider_id=#{providerId}
where app_user_id=#{appUserId}
